class ETGAccrualTransactionReportController extends SrsReportRunController
{
    SRSPrintDestinationSettings printDestinationSetting;
}

Method.Source:
public static ETGAccrualTransactionReportController construct()
{
    return new ETGAccrualTransactionReportController();
}

public static void main(Args _args)
{
    ETGAccrualTransactionReportController controller = ETGAccrualTransactionReportController::construct();

    controller.parmArgs(_args);
    controller.parmReportName(ssrsReportStr(ETGAccrualTransactionReport, ReportNew));
    controller.startOperation();
}

protected void preRunModifyContract()
{
    ETGAccrualTransactionReportContract contract = this.parmReportContract().parmRdpContract() as ETGAccrualTransactionReportContract;
    this.parmReportContract().parmReportName(ssrsReportStr(ETGAccrualTransactionReport, ReportNew));

    printDestinationSetting = new SRSPrintDestinationSettings();
    printDestinationSetting.printMediumType(SRSPrintMediumType::File);
    printDestinationSetting.fileName(System.IO.Path::GetTempPath() +'Accrual_Transaction_Report.xlsx');
    printDestinationSetting.fileFormat(SRSReportFileFormat::Excel); // Select your desire format here
    printDestinationSetting.overwriteFile(true);

    this.parmReportContract().parmPrintSettings(printDestinationSetting);
}
